B.a_c=s(["4 Douglasie-Rahmenh\xf6lzer 90\xd790 (3 m) je auf 2,8 m abl\xe4ngen \u2013 4 durchgehende Bretter f\xfcr 2 Balken (Restst\xfcck 20 cm).","Je Balkenseite 2 Bretter deckungsgleich aufeinanderlegen (untere + obere Lage).","Kontaktfl\xe4chen vollfl\xe4chig mit D4-Leim bestreichen.","Beide Lagen alle ~20 cm mit 8\xd7100-Schrauben (versetzt) verschrauben.","Ergebnis: 2 durchgehende Doppelbalken \xe0 2,8 m \u2013 ohne Stoss."],t.s)
B.a06=s(["assets/bau/01_doppelbalken.png"],t.s)
B.LC=new A.eO("doppelbalken","Doppelbalken bauen",B.a_c,"Bretter gerade und b\xfcndig verleimt; keine St\xf6sse.","Durchgehende Bretter = maximale Steifigkeit. Die zwei verleimten Lagen wirken zugleich gegen Verzug \u2013 D4-Leim (wasserfest) vollfl\xe4chig auftragen.",B.a06)
B.YP=s(["Fester, sonniger, windgesch\xfctzter Platz; Flugl\xf6cher sp\xe4ter nach S\xfcdost, Flugbahn 2\u20133 m frei, hinten 80\u2013100 cm Arbeitsraum.","Rechteck 2000 \xd7 400 mm anzeichnen: Beinabstand l\xe4ngs 2000 mm, Balkenachse (vorn/hinten) 400 mm.","Beine ~400 mm von den Enden einr\xfccken.","Rechtwinkligkeit mit einer Latten-Lehre und gleichen Diagonalen pr\xfcfen."],t.s)
B.a1k=s(["assets/bau/02_draufsicht_rechteck.png"],t.s)
B.LM=new A.eO("rechteck","Standort & Rechteck anzeichnen",B.YP,"Beinabstand 2000 mm, Achse 400 mm, Diagonalen gleich.",null,B.a1k)
B.a0d=s(["4\xd7 Krinner U-FIX 91 an den angezeichneten Punkten ansetzen.","Mit einem Stahlstab durch die Aufnahme lotrecht eindrehen.","Mit der Wasserwaage an der H\xfclse laufend die Senkrechte kontrollieren.","Die 4 Aufnahmen grob auf gleiche H\xf6he bringen (Feinausgleich folgt \xfcber die Bolzen)."],t.s)
B.ZY=s(["assets/bau/03_erdschraube_lot.png"],t.s)
B.Lz=new A.eO("erdschrauben","Erdschrauben eindrehen",B.a0d,"Jede Erdschraube lotrecht; Positionen = angezeichnetes Rechteck.","Auf Steine/Wurzeln achten \u2013 notfalls Schraube leicht versetzen, das Rechteck aber halten.",B.ZY)
B.a0e=s(["4 Pfosten aus Douglasie 90\xd790 auf ~120 mm zuschneiden.","Je Pfosten in eine U-FIX-Aufnahme stellen.","Seitlich mit 8\xd7100-Schraube durchbolzen."],t.s)
B.Zd=s(["assets/bau/04_pfosten_ufix.png"],t.s)
B.Lt=new A.eO("pfosten","Pfosten setzen",B.a0e,"Pfosten fest, grob gleiche Oberkante.",null,B.Zd)
B.ZQ=s(["In jeden Pfostenkopf mittig 16 mm bohren (Forstner-/Holzbohrer).","Einschlagmutter M16 b\xfcndig einsetzen.","Sechskantschraube M16\xd7100 eindrehen, grosse Auflagescheibe auflegen.","Kontermutter aufsetzen, aber noch NICHT kontern (Feinjustage folgt beim Nivellieren)."],t.s)
B.x_=s(["assets/bau/05_nivellierbolzen.png"],t.s)
B.Lw=new A.eO("nivellierbolzen","Nivellier-Bolzen einbauen",B.ZQ,"Schraube leichtg\xe4ngig, Scheibe plan, Verstellweg \xb125 mm frei.",null,B.x_)
B.a1Y=s(["Die 2 Doppelbalken auf die 4 Auflagescheiben legen (Achse 400 mm).","Mit Kreuzlinienlaser oder Schlauchwaage die 4 Bolzen in EINE Ebene drehen \u2013 in L\xe4ngs- UND Querrichtung waagerecht.","Kontermuttern fest anziehen.","Jeden Balken mit 2 Schwerlast-Winkeln (90\xd790\xd765) auf den Pfosten sichern (8 Winkel gesamt)."],t.s)
B.Y5=s(["assets/bau/06_querschnitt_aufbau.png","assets/bau/05_nivellierbolzen.png"],t.s)
B.Ly=new A.eO("nivellieren","Balken auflegen & nivellieren",B.a1Y,"Balken-Oberkante waagerecht l\xe4ngs UND quer; Kontermuttern fest.","Schl\xfcsselschritt \u2013 hier entsteht die ebene, r\xfcckenschonende H\xf6he. Ruhig mehrfach nachmessen.",B.Y5)
B.Za=s(["4 Platten 560 \xd7 500 mm aus der Schaltafel zuschneiden (falls nicht im Markt geschnitten).","Alle Schnittkanten SOFORT versiegeln (Hirnholz zuerst) \u2013 gr\xf6sster Langlebigkeits-Faktor.","Je Platte 2\u20134 Entw\xe4sserungsl\xf6cher \xd8 8 mm bohren."],t.s)
B.Zt=s(["assets/bau/07_platte_entwaesserung.png"],t.s)
B.LK=new A.eO("platten_zuschnitt","Platten zuschneiden & versiegeln",B.Za,"Kanten rundum versiegelt; L\xf6cher gebohrt.",null,B.Zt)
B.ZC=s(["Je Platte mittig \xfcber beide Balken legen (fasst die Waage 500\xd7430 mit Rand).","Von oben mit Terrassenschraube A2 5\xd750 verschrauben (steift den Stand aus).","Jede Platte mit der Wasserwaage pr\xfcfen."],t.s)
B.a1Q=s(["assets/bau/08_platte_auf_balken.png"],t.s)
B.LE=new A.eO("platten_montage","Platten aufschrauben",B.ZC,"Jede Platte waagerecht (wichtig f\xfcr Waagengenauigkeit); V\xf6lkerabstand \u2248 265 mm, Plattenl\xfccke ~160 mm.",null,B.a1Q)
B.a07=s(["Ganzen Stand mit Holz\xf6l/UV-Lasur behandeln, v. a. Hirnholz und Schnittkanten.","Trocknungszeit laut Hersteller einhalten."],t.s)
B.x3=s(["assets/bau/10_seitenansicht_gesamt.png"],t.s)
B.LG=new A.eO("oel","\xd6len & lasieren",B.a07,"Kein blankes Hirnholz mehr; alle Fl\xe4chen behandelt.","Unbehandeltes Douglasie ist bienenfreundlich \u2013 nur aussen/Kanten sch\xfctzen, keine Biozide an der Beute.",B.x3)
B.a_r=s(["HiveWatch-Waage je Platte LOSE auflegen \u2013 nichts seitlich \xfcberbr\xfccken (keine Steine/Leisten).","3-m-Kabel in einer Kantennut am Pfosten herabf\xfchren, Logger gesch\xfctzt platzieren.","Waagen tarieren.","Beuten aufsetzen (Reihenfolge Platte \u2192 Waage \u2192 Beute), Flugrichtung S\xfcdost pr\xfcfen, kalibrieren."],t.s)
B.YZ=s(["assets/bau/09_waagenstapel.png"],t.s)
